/**
 * Type declarations for the Emscripten-compiled curve25519 WASM module.
 * Generated by scripts/compile.js via emscripten.
 */

interface Curve25519EmscriptenModule {
    /** Allocate `size` bytes on the WASM heap. Returns a pointer (number). */
    _malloc(size: number): number;

    /** Free memory at the given pointer. */
    _free(ptr: number): void;

    /** Curve25519 Diffie-Hellman key agreement.
     *  @param out_ptr Pointer to 32-byte output buffer
     *  @param priv_ptr Pointer to 32-byte private key
     *  @param base_ptr Pointer to 32-byte base point
     *  @returns 0 on success, non-zero on error
     */
    _curve25519_donna(out_ptr: number, priv_ptr: number, base_ptr: number): number;

    /** Ed25519 signing (cross-curve variant for OMEMO).
     *  @param sig_ptr Pointer to 64-byte output signature buffer
     *  @param priv_ptr Pointer to 32-byte private key
     *  @param msg_ptr Pointer to message buffer
     *  @param msg_len Length of message in bytes
     *  @returns 0 on success, non-zero on error
     */
    _xed25519_sign(
        sig_ptr: number,
        priv_ptr: number,
        msg_ptr: number,
        msg_len: number
    ): number;

    /** Ed25519 verification (cross-curve variant for OMEMO, sign-bit forced to zero).
     *  @param sig_ptr Pointer to 64-byte signature
     *  @param pub_ptr Pointer to 32-byte public key
     *  @param msg_ptr Pointer to message buffer
     *  @param msg_len Length of message in bytes
     *  @returns 0 if signature is valid, non-zero if invalid
     */
    _xed25519_verify(
        sig_ptr: number,
        pub_ptr: number,
        msg_ptr: number,
        msg_len: number
    ): number;

    /** Ed25519 verification (legacy variant, reads sign bit from signature).
     *  @param sig_ptr Pointer to 64-byte signature
     *  @param pub_ptr Pointer to 32-byte public key
     *  @param msg_ptr Pointer to message buffer
     *  @param msg_len Length of message in bytes
     *  @returns 0 if signature is valid, non-zero if invalid
     */
    _curve25519_verify(
        sig_ptr: number,
        pub_ptr: number,
        msg_ptr: number,
        msg_len: number
    ): number;

    /** SHA-512 context initialization (internal use). */
    _sph_sha512_init(ctx_ptr: number): void;

    /** Ed25519 base point scalar multiplication (internal use). */
    _crypto_sign_ed25519_ref10_ge_scalarmult_base(out_ptr: number, priv_ptr: number): void;

    /** Convert a Curve25519 public key to its Ed25519 public key, sign bit 0 (for OMEMO 2).
     *  @param ed_pub_ptr Pointer to 32-byte output Ed25519 public key buffer
     *  @param curve_pub_ptr Pointer to 32-byte Curve25519 public key
     */
    _curve25519_pubkey_to_ed25519_pubkey(ed_pub_ptr: number, curve_pub_ptr: number): void;

    /** Convert an Ed25519 public key to its Curve25519 public key (for OMEMO 2 DH).
     *  @param curve_pub_ptr Pointer to 32-byte output Curve25519 public key buffer
     *  @param ed_pub_ptr Pointer to 32-byte Ed25519 public key
     */
    _ed25519_pubkey_to_curve25519_pubkey(curve_pub_ptr: number, ed_pub_ptr: number): void;

    /** WASM heap — a typed array view of the module's linear memory. */
    HEAPU8: Uint8Array;
    HEAP32: Int32Array;
    HEAPU32: Uint32Array;

    /** Promise that resolves when the WASM module is ready. */
    ready: Promise<void>;
}

interface Curve25519ModuleOptions {
    /** Override file location for the .wasm binary. */
    locateFile?: (path: string) => string;

    /** Pre-allocated wasm binary (for environments without fetch). */
    wasmBinary?: ArrayBuffer;

    /** Called when the module is ready. */
    onRuntimeInitialized?: () => void;
}

/**
 * Emscripten module factory function.
 * Call with optional options, returns a Promise that resolves to the module.
 */
declare function Curve25519Module(
    options?: Curve25519ModuleOptions
): Promise<Curve25519EmscriptenModule>;

export default Curve25519Module;
export { Curve25519EmscriptenModule, Curve25519ModuleOptions };
